function LBubbleBase:IsBubbleTranValid()
    return self._disObj and self._disObj:IsDpValid()
end

function LBubbleBase:SetBubbleContent()
    if not self:IsBubbleTranValid() then return end
    
    self:OnSetBubbleContent(self._bubbleTran,self._data)
end

function LBubbleBase:RefreshContent(data)
    self._data = data
    self:SetBubbleContent()
end

function LBubbleBase:InitBubbleRoot()
    local rootCanvas = LGameUI.GetUIFight()
    self._uiCamera = LGameUI.GetUICamera()
    self._sceneCamera = gLGameScene:GetCurrentSceneCamera()

    local parentTrans = CS.FindTrans(rootCanvas,LBubbleBase.ROOT)
    if not parentTrans then
        parentTrans = CS.NewObject(LBubbleBase.ROOT, rootCanvas)
    end
    self._parentTrans = parentTrans
end

function LBubbleBase:OnLoaded()
    local tran = self._disObj:GetDisplayTrans()
    self._bubbleTran = tran
    self:SetBubbleContent()
end

function LBubbleBase:SetFollow(tran,offset)
    if not self:IsBubbleTranValid() then return end

    self._bubbleTran.transform:SetParent(tran,false)
    self._bubbleTran.transform.localPosition = offset
end

-----------------------------------------

function LBubbleBase:CreateBubble(data)
    self._data = data
    self:InitBubbleRoot()
    if self:IsBubbleTranValid() then
        self:SetBubbleContent()
        return
    end

    local resName,path,name = self:GetPrefabPath()
    if string.isempty(path) or string.isempty(name) then return end

    if self._disObj then return end

    local disObj = LDisplayPrefab:New()
    self._disObj = disObj
    disObj:CreatePrefab(self._parentTrans,path,name)
    disObj:SetLoadedFunction(function ()
        self:OnLoaded()
    end)
    disObj:StartLoad()
end

