end

function LBubbleBase:Destroy()
    if self._isDetroyed then return end

    if self._seqCom then
        self._seqCom:Destroy()
        self._seqCom = nil
    end

    if self._disObj then
        self._disObj:Destroy()
        self._disObj = nil
    end

    if self._timer then
        self._timer:Destroy()
    end

    LWonderBase.Destroy(self)

    table.removeall(self)
    self._isDetroyed = true

end

